FROM jsonb_to_recordset('[{"id": "cap-107-chinese-passage-34", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下文章，並回答34～35題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "最近仰光進入雨季，我看著路上行人的拖鞋，想到多年前初到緬甸工作時發\n生的事。\n緬甸的正式服裝，無論男女，一定是長到腳踝的沙龍配上紅色呢絨面的牛皮\n拖鞋。既然穿拖鞋的時間這麼多，舒適度就很重要。但奇怪的是，緬甸人在我眼\n中好「沒常識」，總喜歡買小一號的拖鞋，感覺腳跟都露在外面，看了就覺得不\n舒服。\n直到一個當地朋友解釋給我聽：「緬甸雨季長，要是拖鞋比腳長，每走一步\n就會將雨水濺起來，弄溼沙龍的下擺。」\n原來「鞋子要比腳大一點點比較好」這種想法，完全不適用生活在一年有半年\n是雨季地方的人。如果用我們已知的想法看待緬甸人，自然覺得他們莫名其妙，又\n不是說小一點的鞋子用料就可以少一點、價格便宜一點，何必那麼委屈呢？\n實際上，我問了其他東南亞國家的朋友，尤其是印尼人，也覺得鞋子長度不\n能超過腳丫子，是理所當然的「常識」。\n從那一刻起，我學會了_____________________________________。\n我在工作跟生活當中，每次聽到某些人鼻孔哼氣，說「這用腳底想也知道」，\n或是「那根本就是常識啊」，總是會為對方冒一陣冷汗，一個不知道自己認知的常\n識並非放諸四海皆準的人，恐怕才是最欠缺常識、被人當作笑話談論的那個。\n去過世界越多地方，我越覺得自己常識不足。夏天在公眾運輸工具上，若有\n人坐在一個位置上很久剛起身，我們一定嫌熱不會想去坐。我去埃及唸書，卻發\n現即使旁邊還有空位，大家都會去搶別人剛剛坐過的座位，原來剛坐過的位置最\n涼爽，因為人的體溫只有攝氏37度，但外面的氣溫高達45度。這種埃及人一定都\n知道的「常識」，任何一個來自夏天不會超過37度國家的人，都絕對不會有。\n我的眼睛朝著自己的腳望去，只看得到腳背，完全看不到腳下的拖鞋，「嗯，\n這雙大小剛剛好啊！」我在心裡跟自己說，起身走進雨中的仰光，滿心愉悅！\n――改寫自褚士瑩〈大小剛好的鞋子〉", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下文章，並回答34～35題：", "child_qnums": [34, 35]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-36", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下圖表，並回答36～37題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下圖表，並回答36～37題：", "child_qnums": [36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-38", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答38～39題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "封禪泰山是評價一個皇帝在任期間功績的標準，作為曠世盛典，儀式極為\n隆重。泰山 天柱峰的西北側，有一塊高大的石碑，上面刻著「古登封臺」四個\n大字，就是歷代帝王到泰山告祭的封祀臺。帝王登泰山頂築壇祭天叫「封」，\n然後到泰山下面的梁甫或其他山上辟基祭地叫「禪」。封禪極其勞民傷財，一\n般是內風調雨順、外無強敵窺伺的年代，帝王才敢上泰山。但是看看泰山歷\n史，盛世皇帝如唐太宗就沒上山，大概是好大喜功的帝王，如秦始皇、漢武\n帝、唐玄宗等才會封禪表揚自己，亡國的秦二世也封禪，他的封禪刻石是丞相\n李斯篆書鐫刻而成。\n――改寫自吳真《唐詩地圖》", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答38～39題：", "child_qnums": [38, 39]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-40", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答40～41題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "市場上真正重要、甚至可以救命的藥品其實正日漸稀少。一旦被藥廠認定\n不會帶來利潤的藥，馬上就會停止生產。有時候，藥廠決定停止生產重要藥品\n的原因，是想騰出生產線來製造其他更有利潤的藥物。\n美國 食品藥物管理局規定：藥廠決定停產具有「醫療必要」的專賣藥品\n時，需要在六個月前提出。但這項規定卻形同具文，無人遵守。2001年就有很\n多重要藥品出現嚴重短缺，包括一些麻醉藥、治療蛇毒的抗蛇毒血清、早產兒\n用的類固醇、血友病的抗凝血藥、心臟衰竭用的注射藥，以及成人流感與肺炎\n疫苗。\n短缺情況最嚴重的是小兒疫苗。在2000年時，白喉、破傷風、百日咳三合一\n的疫苗數量不足，美國 疾病管制局只好建議：嬰兒只需要接種標準五劑中的前\n三劑就好，並取消追加注射。疾管局還建議延期注射麻疹、腮腺炎和德國麻疹疫\n苗，以及天花疫苗的二次接種。2002年底，疫苗供應情況稍稍回穩，疾管局才又\n建議回歸原始的接種程序。這個問題一直無法徹底解決，原因是製造疫苗的藥廠\n越來越少，比起二十年前約十六家的榮景，現在只有區區四家在生產。\n――改寫自瑪西亞．安卓《藥廠黑幕》", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答40～41題：", "child_qnums": [40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-42", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答42～43題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "「旁若無人」的精神表現在日常行為上者不只一端，其中經常令人困惱的\n乃是高聲談話。在喊救命的時候，聲音當然不嫌其大，除非是脖子被人踩在腳\n底下，但是普通的談話令人聽見即可，而無須一定要力竭聲嘶的去振聾發聵。\n生理學告訴我們，發音的構造是很複雜的，說話一分鐘要有九百個動作，有\n一百塊筋肉在弛張，但是大多數人似乎還嫌不足，恨不得嘴上再長一個擴大\n器。有個外國人疑心我們國人的耳鼓生得異樣，那層膜許是特別厚，非扯著脖\n子喊不能聽見，所以說話總是像打架。這批評有多少真理，我不知道。不過我\n們國人會嚷的本領，是誰也不能否認的。電影場裡電燈初滅時候，總有幾聲\n「噯喲，小三兒，你在哪兒哪？」在戲院裡，演員像是演啞劇，大鑼大鼓之聲\n依稀可聞，主要的聲音是觀眾鼎沸，令人感覺好像是置身蛙塘。在旅館裡，好\n像前後左右都是廟會，不到夜深休想安眠，安眠之後難免有響皮底的大皮靴，\n毫無慚愧的在你門前踱來踱去。天未亮，又有各種市聲前來侵擾。一個人大聲\n說話，是本能；小聲說話，是文明。以動物而論，獅吼，狼嗥，虎嘯，驢鳴，\n犬吠，即使是小如促織蚯蚓，聲音都不算小，都不會像人似的有時候也會低聲\n說話。大概文明程度愈高，說話愈不以聲大見長。群居習慣愈久，愈不容易存\n留「旁若無人」的幻覺，我們以農立國，鄉間地曠人稀，畎畝阡陌之間，低聲\n說一句「早安」是不濟事的，必得扯長了脖子喊一聲「你吃過飯啦？」可怪的\n是，在人煙稠密的所在，人的喉嚨還是不能縮小。更可異的是，紙驢嗓，破鑼\n嗓，喇叭嗓，公雞嗓，並不被一般人認為是缺陷，而且「麻衣相法」還公然的\n說，聲音洪亮者主貴！\n――改寫自梁實秋〈旁若無人〉", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答42～43題：", "child_qnums": [42, 43]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-44", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答44～46題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "朱梁時，青州有賈客泛海遇風，飄至一處，遠望有山川城郭。海師曰：\n「往昔遭風，未嘗至此。吾聞鬼國在是，莫非此耶？」頃之，舟至岸，因登\n岸，向城而去。其廬舍田畝，不殊中國。見人皆揖之，而人皆不見己。至城，\n有守門者，揖之，亦不應。入城，屋室人物甚殷，遂至王宮。正值大宴，群臣\n侍宴者數十，其器用絲竹陳設之類，多類中國。客因升殿，俯逼王座以窺之。\n俄而王有疾，左右扶還，亟召巫者視之。巫至，曰：「有陽地人至此，陽氣逼\n人，故王病。其人偶來爾，無心為祟，以飲食車馬謝遣之，可矣。」即具酒\n食，設座於別室，巫及其群臣皆來祀祝，客據案而食。俄有僕夫馭馬而至，\n客亦乘馬而歸，至岸登舟，國人竟不見己，復遇便風得歸。時賀德儉為青州節\n度，與魏博節度楊師厚有親，因遣此客使魏，其為師厚言之。魏人范宣古親聞\n其事，為余言。\n――改寫自《太平廣記．青州客》", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答44～46題：", "child_qnums": [44, 45, 46]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-107-chinese-passage-47", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-107-chinese", "question_type": "reading_passage", "question_text": "請閱讀以下短文，並回答47～48題：", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "有疑陶淵明詩篇篇有酒，吾觀其意不在酒，亦寄酒為跡者也。其文章不\n群，辭采精拔，跌宕昭彰，獨超眾類，抑揚爽朗，莫之與京 1。橫素波而傍流，\n干青雲而直上。語時事則指而可想，論懷抱則曠而且真。加以貞志不休，安道\n苦節，不以躬耕為恥，不以無財為病。自非大賢篤志，孰能如此乎？余愛嗜其\n文，不能釋手，尚想其德，恨不同時。\n――改寫自蕭統〈陶淵明集序〉\n", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "2d7d32b90c63", "answer_pdf_sha1": "05a67d1d6082", "flags": [], "parse_confidence": null, "intro_line": "請閱讀以下短文，並回答47～48題：", "child_qnums": [47, 48]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
